#!/usr/bin/env bash
set -Eeuo pipefail

# ============================================================
# sc_deploy.sh - Unified interactive entry for Hadoop deploy
# Self-contained mode: embeds sc_all.sh / sc_master.sh / run_hadoop.sh
# ============================================================

SCRIPT_NAME="$(basename "$0")"
WORKDIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
CONF_PATH="${WORKDIR}/cluster.conf"

EMBEDDED_DIR=""
EMBEDDED_SC_ALL_B64=""
EMBEDDED_SC_MASTER_B64=""
EMBEDDED_RUN_HADOOP_B64=""

log() { echo "[$(date '+%F %T')] $*"; }
die() { log "ERROR: $*"; exit 1; }

cleanup_embedded() {
  if [[ -n "${EMBEDDED_DIR}" && -d "${EMBEDDED_DIR}" ]]; then
    rm -rf "${EMBEDDED_DIR}" || true
  fi
}
trap cleanup_embedded EXIT

require_root() {
  [[ "${EUID}" -eq 0 ]] || die "请使用 root 或 sudo 运行：sudo ./${SCRIPT_NAME}"
}

require_files() {
  [[ -f "${CONF_PATH}" ]] || die "未找到 ${CONF_PATH}"
}

load_config() {
  # shellcheck disable=SC1090
  source "${CONF_PATH}"

  : "${MASTER_HOSTNAME:?cluster.conf 缺少 MASTER_HOSTNAME}"
  : "${WORKER1_HOSTNAME:?cluster.conf 缺少 WORKER1_HOSTNAME}"
  : "${WORKER2_HOSTNAME:?cluster.conf 缺少 WORKER2_HOSTNAME}"
  : "${DEFAULT_IP_MASTER:?cluster.conf 缺少 DEFAULT_IP_MASTER}"
  : "${DEFAULT_IP_WORKER1:?cluster.conf 缺少 DEFAULT_IP_WORKER1}"
  : "${DEFAULT_IP_WORKER2:?cluster.conf 缺少 DEFAULT_IP_WORKER2}"
}

validate_ipv4() {
  local ip="$1"
  if [[ ! "$ip" =~ ^([0-9]{1,3}\.){3}[0-9]{1,3}$ ]]; then
    return 1
  fi
  IFS='.' read -r o1 o2 o3 o4 <<< "$ip"
  for o in "$o1" "$o2" "$o3" "$o4"; do
    [[ "$o" -ge 0 && "$o" -le 255 ]] || return 1
  done
  return 0
}

guess_role_by_hostname() {
  local hn
  hn="$(hostnamectl --static 2>/dev/null || hostname)"
  case "${hn}" in
    "${MASTER_HOSTNAME}") echo "master" ;;
    "${WORKER1_HOSTNAME}") echo "worker1" ;;
    "${WORKER2_HOSTNAME}") echo "worker2" ;;
    *) echo "" ;;
  esac
}

default_ip_for_role() {
  case "$1" in
    master) echo "${DEFAULT_IP_MASTER}" ;;
    worker1) echo "${DEFAULT_IP_WORKER1}" ;;
    worker2) echo "${DEFAULT_IP_WORKER2}" ;;
    *) echo "" ;;
  esac
}

write_b64_file() {
  local b64="$1"
  local target="$2"

  if command -v base64 >/dev/null 2>&1; then
    printf '%s' "$b64" | base64 -d > "$target"
    return 0
  fi

  if command -v openssl >/dev/null 2>&1; then
    printf '%s' "$b64" | openssl base64 -d -A > "$target"
    return 0
  fi

  die "未找到 base64/openssl，无法解包内置脚本"
}

ensure_embedded_scripts() {
  if [[ -n "${EMBEDDED_DIR}" && -x "${EMBEDDED_DIR}/sc_all.sh" && -x "${EMBEDDED_DIR}/sc_master.sh" && -x "${EMBEDDED_DIR}/run_hadoop.sh" ]]; then
    return 0
  fi

  EMBEDDED_DIR="$(mktemp -d /tmp/hadoop_deploy_embedded.XXXXXX)"

  write_b64_file "${EMBEDDED_SC_ALL_B64}" "${EMBEDDED_DIR}/sc_all.sh"
  write_b64_file "${EMBEDDED_SC_MASTER_B64}" "${EMBEDDED_DIR}/sc_master.sh"
  write_b64_file "${EMBEDDED_RUN_HADOOP_B64}" "${EMBEDDED_DIR}/run_hadoop.sh"

  chmod 700 "${EMBEDDED_DIR}/sc_all.sh" "${EMBEDDED_DIR}/sc_master.sh" "${EMBEDDED_DIR}/run_hadoop.sh"
}

exec_sc_all() {
  ensure_embedded_scripts
  bash "${EMBEDDED_DIR}/sc_all.sh" "$@"
}

exec_sc_master() {
  ensure_embedded_scripts
  bash "${EMBEDDED_DIR}/sc_master.sh" "$@"
}

exec_run_hadoop() {
  ensure_embedded_scripts
  bash "${EMBEDDED_DIR}/run_hadoop.sh" "$@"
}

prompt_role() {
  local guessed="$1"
  local choice role=""

  echo
  echo "请选择当前机器角色："
  echo "  1) master"
  echo "  2) worker1"
  echo "  3) worker2"
  if [[ -n "${guessed}" ]]; then
    echo "检测到主机名推测角色：${guessed}"
  fi

  while true; do
    if [[ -n "${guessed}" ]]; then
      read -r -p "输入序号 [1-3] (回车默认 ${guessed}): " choice
    else
      read -r -p "输入序号 [1-3]: " choice
    fi
    case "${choice}" in
      1) role="master"; break ;;
      2) role="worker1"; break ;;
      3) role="worker2"; break ;;
      "")
        if [[ -n "${guessed}" ]]; then
          role="${guessed}"
          break
        fi
        ;;
      *) echo "无效输入，请重试。" ;;
    esac
  done

  echo "${role}"
}

prompt_ip() {
  local role="$1"
  local def_ip ip
  def_ip="$(default_ip_for_role "${role}")"

  while true; do
    read -r -p "请输入当前机器静态 IP (回车默认 ${def_ip}): " ip
    ip="${ip:-${def_ip}}"
    if validate_ipv4 "${ip}"; then
      echo "${ip}"
      return 0
    fi
    echo "IP 格式不合法，请重新输入。"
  done
}

run_sc_all_interactive() {
  local guessed role ip
  guessed="$(guess_role_by_hostname)"
  role="$(prompt_role "${guessed}")"
  ip="$(prompt_ip "${role}")"

  echo
  log "准备执行：sc_all.sh role=${role}, ip=${ip}"
  exec_sc_all "${role}" --conf "${CONF_PATH}" --ip "${ip}"
}

prompt_master_module() {
  local choice module
  echo
  echo "请选择集群安装模块："
  echo "  1) ssh     (配置免密)"
  echo "  2) install (安装并分发 JDK+Hadoop)"
  echo "  3) config  (写入并分发 Hadoop 配置)"
  echo "  4) all     (按 ssh -> install -> config 全流程)"

  while true; do
    read -r -p "输入序号 [1-4] (回车默认 4): " choice
    case "${choice}" in
      1) module="ssh"; break ;;
      2) module="install"; break ;;
      3) module="config"; break ;;
      4|"") module="all"; break ;;
      *) echo "无效输入，请重试。" ;;
    esac
  done

  echo "${module}"
}

prompt_yes_no() {
  local prompt="$1"
  local answer
  while true; do
    read -r -p "${prompt} [y/N]: " answer
    case "${answer}" in
      y|Y|yes|YES) return 0 ;;
      n|N|no|NO|"") return 1 ;;
      *) echo "请输入 y 或 n。" ;;
    esac
  done
}

run_sc_master_interactive() {
  local module force_arg=""
  local hn
  hn="$(hostnamectl --static 2>/dev/null || hostname)"

  if [[ "${hn}" != "${MASTER_HOSTNAME}" ]]; then
    echo
    echo "警告：当前主机名是 ${hn}，不是配置中的 master(${MASTER_HOSTNAME})。"
    echo "继续执行通常会被 sc_master.sh 拒绝。"
    if ! prompt_yes_no "是否仍然继续尝试执行"; then
      log "已取消执行 sc_master.sh"
      return 0
    fi
  fi

  module="$(prompt_master_module)"
  if prompt_yes_no "是否启用强制重装 (--force)"; then
    force_arg="--force"
  fi

  echo
  log "准备执行：sc_master.sh --module ${module} ${force_arg}"
  if [[ -n "${force_arg}" ]]; then
    exec_sc_master --conf "${CONF_PATH}" --module "${module}" --force
  else
    exec_sc_master --conf "${CONF_PATH}" --module "${module}"
  fi
}

prompt_hadoop_action() {
  local choice action
  echo
  echo "请选择 Hadoop 运维动作："
  echo "  1) start   (启动，首次会自动 format)"
  echo "  2) stop    (停止)"
  echo "  3) restart (重启)"
  echo "  4) status  (状态)"
  echo "  5) health  (健康检查)"
  echo "  6) format  (强制格式化 NameNode，危险)"
  echo "  7) env     (显示环境刷新命令)"
  echo "  8) shell   (打开已加载环境的 shell)"

  while true; do
    read -r -p "输入序号 [1-8] (回车默认 1): " choice
    case "${choice}" in
      1|"") action="start"; break ;;
      2) action="stop"; break ;;
      3) action="restart"; break ;;
      4) action="status"; break ;;
      5) action="health"; break ;;
      6) action="format"; break ;;
      7) action="env"; break ;;
      8) action="shell"; break ;;
      *) echo "无效输入，请重试。" ;;
    esac
  done

  echo "${action}"
}

run_hadoop_interactive() {
  local action hn
  hn="$(hostnamectl --static 2>/dev/null || hostname)"

  if [[ "${hn}" != "${MASTER_HOSTNAME}" ]]; then
    echo
    echo "警告：run_hadoop.sh 只应在 master 执行。当前主机名=${hn}，配置 master=${MASTER_HOSTNAME}"
    if ! prompt_yes_no "是否仍然继续尝试执行"; then
      log "已取消执行 run_hadoop.sh"
      return 0
    fi
  fi

  action="$(prompt_hadoop_action)"
  if [[ "${action}" == "format" ]]; then
    echo
    echo "危险操作提示：format 会清空 NameNode 元数据。"
    if ! prompt_yes_no "确认继续执行 format"; then
      log "已取消 format"
      return 0
    fi
  fi

  echo
  log "准备执行：run_hadoop.sh ${action}"
  exec_run_hadoop "${action}" --conf "${CONF_PATH}"
}

run_one_click() {
  local hn module
  hn="$(hostnamectl --static 2>/dev/null || hostname)"

  run_sc_all_interactive

  if [[ "${hn}" == "${MASTER_HOSTNAME}" ]]; then
    echo
    if prompt_yes_no "检测到当前是 master，是否继续执行 sc_master.sh"; then
      module="$(prompt_master_module)"
      log "准备执行一键流程中的 master 模块：${module}"
      exec_sc_master --conf "${CONF_PATH}" --module "${module}"

      echo
      if prompt_yes_no "是否继续启动 Hadoop 集群 (run_hadoop.sh start)"; then
        exec_run_hadoop start --conf "${CONF_PATH}"
      fi

      echo
      if prompt_yes_no "是否立刻执行健康检查 (run_hadoop.sh health)"; then
        exec_run_hadoop health --conf "${CONF_PATH}"
      fi
    else
      log "已跳过 sc_master.sh"
    fi
  else
    log "当前不是 master，已完成本机初始化。"
  fi
}

show_main_menu() {
  echo
  echo "========================================="
  echo "Hadoop 集群部署统一入口 (${SCRIPT_NAME})"
  echo "配置文件: ${CONF_PATH}"
  echo "========================================="
  echo "1) 初始化当前节点 (内置 sc_all 逻辑)"
  echo "2) 在 master 执行集群安装/分发 (内置 sc_master 逻辑)"
  echo "3) 一键流程 (节点初始化 + master安装分发 + 可选启动检查)"
  echo "4) Hadoop 启停/状态/健康检查 (内置 run_hadoop 逻辑)"
  echo "5) 退出"
}

main() {
  require_root
  require_files
  load_config

  while true; do
    local choice
    show_main_menu
    read -r -p "请选择 [1-5]: " choice
    case "${choice}" in
      1) run_sc_all_interactive ;;
      2) run_sc_master_interactive ;;
      3) run_one_click ;;
      4) run_hadoop_interactive ;;
      5) log "退出。"; break ;;
      *) echo "无效输入，请重试。" ;;
    esac
  done
}

main "$@"